// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column?: string; title?: string; assignee?: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Helper: Get priority badge variant
const getPriorityVariant = (priority?: string) => {
  switch (priority) {
    case 'high': return 'error';
    case 'medium': return 'warning';
    case 'low': return 'success';
    default: return 'default';
  }
};

// Helper: Get priority label
const getPriorityLabel = (priority?: string) => {
  return priority ? priority.charAt(0).toUpperCase() + priority.slice(1) : 'None';
};

// Helper: Get initials from assignee
const getInitials = (assignee?: string) => {
  if (!assignee) return '';
  const parts = assignee.split(' ');
  if (parts.length > 1) return (parts[0][0] + parts[1][0]).toUpperCase();
  return assignee.substring(0, 2).toUpperCase();
};

// Task Card Sub-component
interface TaskCardProps {
  id?: string;
  title?: string;
  priority?: 'low' | 'medium' | 'high';
  assignee?: string;
  dueDate?: string;
  onMove: (columnId: string) => void;
  onEdit: (title: string) => void;
  columns: Array<{ id?: string; name?: string }>;
  currentColumn?: string;
}

function TaskCard({ id, title, priority, assignee, dueDate, onMove, onEdit, columns, currentColumn }: TaskCardProps) {
  const [isEditing, setIsEditing] = useState(false);
  const [editTitle, setEditTitle] = useState(title || '');
  const initials = getInitials(assignee);

  const handleSaveEdit = () => {
    if (editTitle.trim()) {
      onEdit(editTitle);
      setIsEditing(false);
    }
  };

  const handleCancelEdit = () => {
    setEditTitle(title || '');
    setIsEditing(false);
  };

  const handleDoubleClick = () => {
    setIsEditing(true);
  };

  const handleEditKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleSaveEdit();
    } else if (e.key === 'Escape') {
      handleCancelEdit();
    }
  };

  return (
    <Card padding="var(--ggui-spacing-3)" shadow="sm" radius="md">
      <Stack gap="var(--ggui-spacing-2)">
        {isEditing ? (
          <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
            <Input
              label="Task title"
              value={editTitle}
              onChange={setEditTitle}
              placeholder="Task title"
              size="sm"
              onKeyDown={handleEditKeyDown}
            />
            <Button size="sm" variant="primary" onClick={handleSaveEdit}>
              Save
            </Button>
            <Button size="sm" variant="ghost" onClick={handleCancelEdit}>
              Cancel
            </Button>
          </Stack>
        ) : (
          <Stack gap="var(--ggui-spacing-2)">
            <Row gap="var(--ggui-spacing-2)" align="center" justify="between">
              <Text
                variant="body"
                as={Clickable}
                onClick={handleDoubleClick}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' || e.key === ' ') {
                    e.preventDefault();
                    setIsEditing(true);
                  }
                }}
                tabIndex={0}
                role="button"
                aria-label="Click or press Enter to edit task"
                style={{
                  cursor: 'pointer',
                  padding: 'var(--ggui-spacing-1)',
                  borderRadius: 'var(--ggui-shape-radius-sm)',
                  backgroundColor: 'transparent',
                  transition: 'background-color 200ms ease-in-out',
                  flex: 1,
                }}
                onMouseEnter={(e) => {
                  if (e.currentTarget instanceof HTMLElement) {
                    e.currentTarget.style.backgroundColor = 'var(--ggui-color-primary-50)';
                  }
                }}
                onMouseLeave={(e) => {
                  if (e.currentTarget instanceof HTMLElement) {
                    e.currentTarget.style.backgroundColor = 'transparent';
                  }
                }}
              >
                {title || 'Untitled'}
              </Text>
              <Button
                size="xs"
                variant="ghost"
                onClick={handleDoubleClick}
                aria-label="Edit task title"
              >
                <Icon name="pencil" size={16} />
              </Button>
            </Row>
            {assignee && (
              <Avatar name={assignee} size="sm" shape="circle" aria-label={`Assigned to ${assignee}`} />
            )}
            {dueDate && (
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" size="xs">
                {new Date(dueDate).toLocaleDateString()}
              </Text>
            )}
            <Dropdown
              trigger={<Button size="sm" variant="ghost" aria-label="Move task to another column">Move</Button>}
              options={columns
                .filter(col => col.id !== currentColumn)
                .map(col => ({
                  value: col.id || '',
                  label: col.name || 'Unknown',
                }))}
              value=""
              onChange={(value: string) => onMove(value)}
              placement="bottom-start"
            />
          </Stack>
        )}
      </Stack>
    </Card>
  );
}
}

// Add Task Form Sub-component
interface AddTaskFormProps {
  onSubmit: (title: string, priority: 'low' | 'medium' | 'high', assignee: string) => void;
  onCancel: () => void;
}

function AddTaskForm({ onSubmit, onCancel }: AddTaskFormProps) {
  const [title, setTitle] = useState('');
  const [priority, setPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [assignee, setAssignee] = useState('');

  const handleSubmit = (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (title.trim()) {
      onSubmit(title, priority, assignee);
      setTitle('');
      setPriority('medium');
      setAssignee('');
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <Card padding="var(--ggui-spacing-3)" shadow="sm" radius="md" background="var(--ggui-color-surfaceVariant)">
        <Stack gap="var(--ggui-spacing-2)">
          <Input
            label="Task title"
            value={title}
            onChange={setTitle}
            placeholder="Enter task title"
            size="sm"
          />
          <Input
            label="Assignee"
            value={assignee}
            onChange={setAssignee}
            placeholder="Name or initials"
            size="sm"
          />
          <Select
            label="Priority"
            value={priority}
            onChange={(v) => setPriority(v as 'low' | 'medium' | 'high')}
            options={[
              { value: 'low', label: 'Low' },
              { value: 'medium', label: 'Medium' },
              { value: 'high', label: 'High' },
            ]}
            size="sm"
          />
          <Row gap="var(--ggui-spacing-2)" justify="end">
            <Button size="sm" variant="ghost" onClick={onCancel} type="button">
              Cancel
            </Button>
            <Button size="sm" variant="primary" onClick={() => handleSubmit()} type="submit">
              Add Task
            </Button>
          </Row>
        </Stack>
      </Card>
    </form>
  );
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // State
  const [localTasks, setLocalTasks] = useState(props.tasks || []);
  const [addingColumnId, setAddingColumnId] = useState<string | null>(null);

  // Sync with props
  useEffect(() => {
    setLocalTasks(props.tasks || []);
  }, [props.tasks]);

  // Listen for stream updates from other users
  useEffect(() => {
    if (taskChanged.latest) {
      const event = taskChanged.latest;
      if (event.action === 'delete' && event.task?.id) {
        setLocalTasks(prev => prev.filter(t => t.id !== event.task?.id));
      } else if (event.task?.id) {
        setLocalTasks(prev => {
          const existing = prev.findIndex(t => t.id === event.task?.id);
          if (existing >= 0) {
            const updated = [...prev];
            updated[existing] = { ...updated[existing], ...event.task };
            return updated;
          }
          return [...prev, event.task];
        });
      }
    }
  }, [taskChanged.latest]);

  // Handlers
  const handleMoveTask = (taskId: string, targetColumnId: string) => {
    setLocalTasks(prev =>
      prev.map(t =>
        t.id === taskId ? { ...t, column: targetColumnId } : t
      )
    );
    taskUpdate({
      action: 'move',
      taskId,
      data: { column: targetColumnId },
    });
  };

  const handleEditTask = (taskId: string, newTitle: string) => {
    setLocalTasks(prev =>
      prev.map(t =>
        t.id === taskId ? { ...t, title: newTitle } : t
      )
    );
    taskUpdate({
      action: 'edit',
      taskId,
      data: {
        title: newTitle,
        column: localTasks.find(t => t.id === taskId)?.column || 'todo',
      },
    });
  };

  const handleAddTask = (columnId: string, title: string, priority: 'low' | 'medium' | 'high', assignee: string) => {
    const newTaskId = `task-${Date.now()}`;
    const newTask = {
      id: newTaskId,
      title,
      priority,
      assignee,
      column: columnId,
    };
    setLocalTasks(prev => [...prev, newTask]);
    taskUpdate({
      action: 'create',
      taskId: newTaskId,
      data: { column: columnId, title, assignee },
    });
    setAddingColumnId(null);
  };

  // Computed values
  const totalTasks = localTasks.length;
  const completedTasks = localTasks.filter(t => t.column === 'done').length;
  const getTasksForColumn = (columnId?: string) =>
    localTasks.filter(t => t.column === columnId);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <section aria-label="Task summary">
          <Card padding="var(--ggui-spacing-4)" shadow="sm">
            <Row gap="var(--ggui-spacing-4)" justify="between" align="center">
              <Stack gap="var(--ggui-spacing-1)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                  Task Summary
                </Text>
                <Text variant="bodyLarge" weight="semibold">
                  {totalTasks} Total • {completedTasks} Completed
                </Text>
              </Stack>
              {totalTasks > 0 && (
                <Progress
                  value={completedTasks}
                  max={totalTasks}
                  variant="success"
                  size="md"
                  showLabel
                  aria-label="Task completion progress"
                />
              )}
            </Row>
          </Card>
        </section>

        {/* Kanban Board */}
        <Row
          gap="var(--ggui-spacing-6)"
          align="stretch"
          style={{ minHeight: 'calc(100vh - 400px)' }}
        >
          {props.columns && props.columns.map((column) => {
            const columnTasks = getTasksForColumn(column.id);
            const isAddingHere = addingColumnId === column.id;
            return (
              <section
                key={column.id}
                aria-labelledby={`column-${column.id}-heading`}
                style={{
                  flex: 1,
                  minWidth: 'clamp(280px, 100%, 400px)',
                  background: 'var(--ggui-color-surfaceVariant)',
                  padding: 'var(--ggui-spacing-4)',
                  borderRadius: 'var(--ggui-shape-radius-lg)',
                  overflowY: 'auto',
                  display: 'flex',
                  flexDirection: 'column',
                  gap: 'var(--ggui-spacing-3)',
                }}
              >
                {/* Column Header */}
                <Stack gap="var(--ggui-spacing-2)">
                  <Row gap="var(--ggui-spacing-2)" justify="between" align="center">
                    <Heading level={4}>
                      {column.name}
                    </Heading>
                    <Badge variant="default" size="sm">
                      {columnTasks.length}
                    </Badge>
                  </Row>
                  <Divider margin="var(--ggui-spacing-2)" />
                </Stack>

                {/* Task Cards */}
                <Stack gap="var(--ggui-spacing-2)" style={{ flex: 1 }}>
                  {columnTasks.map((task) => (
                    <TaskCard
                      key={task.id}
                      id={task.id}
                      title={task.title}
                      priority={task.priority}
                      assignee={task.assignee}
                      dueDate={task.dueDate}
                      currentColumn={column.id}
                      columns={props.columns}
                      onMove={(targetColumnId) =>
                        handleMoveTask(task.id || '', targetColumnId)
                      }
                      onEdit={(newTitle) =>
                        handleEditTask(task.id || '', newTitle)
                      }
                    />
                  ))}
                </Stack>

                {/* Add Task Form or Button */}
                {isAddingHere ? (
                  <AddTaskForm
                    onSubmit={(title, priority, assignee) =>
                      handleAddTask(column.id || 'todo', title, priority, assignee)
                    }
                    onCancel={() => setAddingColumnId(null)}
                  />
                ) : (
                  <Button
                    variant="outline"
                    size="md"
                    onClick={() => setAddingColumnId(column.id || null)}
                    fullWidth
                    aria-label={`Add task to ${column.name || 'column'}`}
                  >
                    + Add Task
                  </Button>
                )}
              </section>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}
